const body = $input.first().json.body || $input.first().json;
const query = body.query || '';
const context = body.context || '';
const convokeReason = body.convene_reason || 'general_review';
const requireConsensus = body.require_consensus !== false;

if (!query) throw new Error('Council requires a query. Field: query');

return [{
  json: {
    query,
    context,
    convene_reason: convokeReason,
    require_consensus: requireConsensus,
    convened_at: new Date().toISOString()
  }
}];

