// Collect the six spirit verdicts
const items = $input.all();
const verdicts = [];

for (const item of items) {
  const text = item.json.text || item.json.response || JSON.stringify(item.json);
  let parsed;
  try {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: text };
  } catch (e) {
    parsed = { raw: text, parse_error: e.message };
  }
  verdicts.push(parsed);
}

const rejections = verdicts.filter(v => v.verdict === 'REJECTED');
const conditionals = verdicts.filter(v => v.verdict === 'CONDITIONAL');
const approvals = verdicts.filter(v => v.verdict === 'APPROVED');

return [{
  json: {
    query: $('Prepare Query').first().json.query,
    context: $('Prepare Query').first().json.context,
    six_verdicts: verdicts,
    rejection_count: rejections.length,
    conditional_count: conditionals.length,
    approval_count: approvals.length,
    verdicts_summary: verdicts.map(v => `${v.spirit || 'Unknown'}: ${v.verdict || 'UNKNOWN'}`).join(' | ')
  }
}];

