try {
  const jsonMatch = spirit7Text.match(/\{[\s\S]*\}/);
  spirit7 = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: spirit7Text };
} catch (e) {
  spirit7 = { raw: spirit7Text, parse_error: e.message };
}

return [{
  json: {
    query: tally.query,
    context: tally.context,
    council_verdict: spirit7.council_verdict || 'UNKNOWN',
    constitutional_ruling: spirit7.constitutional_ruling || '',
    synthesis: spirit7.synthesis || '',
